import{_ as t,o as r,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"25. Private Practice Rights","description":"","frontmatter":{"title":"25. Private Practice Rights","eba":"Doctors in Training 2022-2026","topics":["employment"]},"headers":[],"relativePath":"ebas/doctors-in-training/doctor-employment/25-private-practice-rights.md","filePath":"ebas/doctors-in-training/doctor-employment/25-private-practice-rights.md"}'),i={name:"ebas/doctors-in-training/doctor-employment/25-private-practice-rights.md"};function c(n,e,s,p,h,d){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_25-private-practice-rights" tabindex="-1">25. Private Practice Rights <a class="header-anchor" href="#_25-private-practice-rights" aria-label="Permalink to &quot;25. Private Practice Rights&quot;">​</a></h1><p><strong>25.1</strong> A Doctor who has completed the 1st year of experience as an HMO (Intern) may undertake private practice subject to the following, unless otherwise agreed:</p><p><strong>(a)</strong> such practice must not be carried on during Duty Hours; and</p><p><strong>(b)</strong> such practice must not involve Health Service property or be conducted in any respect within the precincts of the Health Service.</p><p><strong>25.2</strong> Doctors may by agreement be on loan to other bodies or practitioners. Agreement must be reached between the Health Service, the Doctor and the other body.</p><p><strong>25.3</strong> The above subclause 25.2 applies to Doctors seconded for service with the Australian Defence Force but does not apply to service under the Defence Act 1903.</p><p>Plain language terms: private practice.</p>',7)])])}const m=t(i,[["render",c]]);export{g as __pageData,m as default};
